agent-browser eval "$(cat <<'EOF'
(function() {
  const results = {};

  // 1. Verify axis labels
  const textElements = Array.from(document.querySelectorAll('text'));
  results.xAxisLabel = textElements.some(el => el.textContent === 'Horsepower');
  results.yAxisLabel = textElements.some(el => el.textContent === 'Miles per Gallon' || el.textContent === 'Miles_per_Gallon');

  // 2. Verify colors at threshold 150
  // Vega-Lite marks often have data bound to them or we can infer from position.
  // A better way is to check the fill color of the symbols.
  // Let's find all path elements that represent points.
  const points = Array.from(document.querySelectorAll('path.mark-symbol'));

  // We need to know which point corresponds to which Horsepower.
  // This is tricky without the original data, but we can check the color distribution.
  // According to the prompt: Horsepower < 150 are steelblue, >= 150 are orange.
  // Since x-axis is Horsepower, points on the left should be steelblue, points on the right orange.

  // Get the x-scale if possible, or just check the colors.
  const colors = points.map(p => p.getAttribute('fill'));
  results.hasSteelblue = colors.includes('steelblue');
  results.hasOrange = colors.includes('orange');

  // Check the boundary.
  // Find the x-coordinates of steelblue and orange points.
  const steelblueX = points.filter(p => p.getAttribute('fill') === 'steelblue').map(p => p.getBoundingClientRect().left);
  const orangeX = points.filter(p => p.getAttribute('fill') === 'orange').map(p => p.getBoundingClientRect().left);

  results.maxSteelblueX = Math.max(...steelblueX);
  results.minOrangeX = Math.min(...orangeX);
  results.initialSteelblueCount = steelblueX.length;
  results.initialOrangeCount = orangeX.length;

  return results;
})()
EOF
)"

agent-browser eval "$(cat <<'EOF'
(function() {
  const points = Array.from(document.querySelectorAll('path[role="graphics-symbol"]'));
  const results = {
    pointsCount: points.length,
    correctlyColored: 0,
    incorrectlyColored: 0,
    steelblueCount: 0,
    orangeCount: 0,
    threshold: 150
  };

  points.forEach(p => {
    const label = p.getAttribute('aria-label');
    if (!label) return;

    const hpMatch = label.match(/Horsepower: ([\d.]+)/);
    if (!hpMatch) return;

    const hp = parseFloat(hpMatch[1]);
    const stroke = p.getAttribute('stroke');

    if (hp < results.threshold) {
      if (stroke === 'steelblue') {
        results.correctlyColored++;
        results.steelblueCount++;
      } else {
        results.incorrectlyColored++;
      }
    } else {
      if (stroke === 'orange') {
        results.correctlyColored++;
        results.orangeCount++;
      } else {
        results.incorrectlyColored++;
      }
    }
  });

  return results;
})()
EOF
)"

agent-browser eval "$(cat <<'EOF'
(function() {
  const slider = document.querySelector('input[type="range"]');
  if (!slider) return "Slider not found";

  slider.value = 200;
  slider.dispatchEvent(new Event('input', { bubbles: true }));
  slider.dispatchEvent(new Event('change', { bubbles: true }));
  return "Slider updated to 200";
})()
EOF
)" && agent-browser wait 2000

